import PageShell from "../(marketing)/page-shell";

export default function PrivacyPage() {
  return (
    <PageShell
      title="Privacy Policy"
      subtitle="A simple overview of how SciSeek handles information."
    >
      <>
        <p>
          SciSeek may collect information you provide directly, such as questions
          you submit, messages you send, or feedback you share.
        </p>

        <p>
          Submitted questions and product usage data may be used to operate,
          improve, and monitor the service.
        </p>

        <p>
          SciSeek may also collect basic technical information such as browser
          type, device information, and general usage analytics.
        </p>

        <p>
          SciSeek does not sell your personal information.
        </p>

        <p>
          If accounts, subscriptions, or additional features are added later,
          this policy may be updated to reflect those changes.
        </p>

        <p>
          By using SciSeek, you agree to this privacy policy.
        </p>
      </>
    </PageShell>
  );
}